-- =============================================================================
-- Goals (all belong to u1)
-- Demonstrates both goal types:
--   ‘measurable’ - has a numeric target and current value; history array shows
--                  progress snapshots used to render the progress chart.
--   ‘completion’  - binary done/not-done; target and current default to 0.
-- History entries: [{ "date": "YYYY-MM-DD", "value": number }, ...]
-- =============================================================================
INSERT INTO goals (id, user_id, title, goal_type, measure, actions, target_date, notes, category, target, current, completed, history) VALUES
